# -*- coding: utf-8 -*-
"""Generate Russian and Ukrainian locale files (manual translations)."""
import json
from pathlib import Path

SRC_ROOT = Path(__file__).resolve().parent.parent


def save(code: str, data: dict[str, str]) -> None:
    en = json.loads((SRC_ROOT / "locales/en.json").read_text(encoding="utf-8"))
    assert set(data) == set(en)
    (SRC_ROOT / f"locales/{code}.json").write_text(
        json.dumps(data, ensure_ascii=False, indent=2) + "\n", encoding="utf-8"
    )
    same = sum(1 for k in en if data[k] == en[k])
    print(f"{code}: {len(en) - same}/{len(en)} ({100 * (len(en) - same) / len(en):.0f}%)")


def build(base: dict[str, str], overrides: dict[str, str]) -> dict[str, str]:
    out = dict(base)
    out.update(overrides)
    return out


es = json.loads((SRC_ROOT / "locales/es.json").read_text(encoding="utf-8"))

